using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tool instances ---
var notepad = new Notepad();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);
var searcher = new WebSearcher(httpClient);

// --- Register AI tools ---
List<AITool> tools =
[
    AIFunctionFactory.Create(searcher.SearchWebAsync),
    AIFunctionFactory.Create(searcher.FetchPageAsync),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetNotes),
];

// --- Build chat client (abstraction layer only — no direct SDK calls) ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. Your workflow is:
        1. Search the web with search_web for relevant information.
        2. Fetch promising pages with fetch_page to get details.
        3. Record every important finding with save_note.
        4. After gathering enough information (at least 3 notes), call get_notes
           to review everything, then write a comprehensive summary.

        Research strategy:
        - Run 2-3 different searches to cover the topic from multiple angles.
        - Fetch the most relevant URLs from the search results.
        - Save a note for each key finding with a descriptive title.
        - Your final answer must be a well-structured summary that synthesizes
          all findings. Include source URLs where possible.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes.",
    tools: tools);

// --- Get topic from the user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}");
Console.WriteLine("Agent is working...\n");

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Please research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n✅ Research complete.");

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>Provides web search and page-fetching tools for the research agent.</summary>
public sealed class WebSearcher(HttpClient httpClient)
{
    [Description("Search the web for information on a topic. Returns titles, URLs, and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: {query}");
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await httpClient.GetStringAsync(url, cancellationToken);
            var results = ParseSearchResults(html);
            return results.Length > 0
                ? results
                : "No results found. Try a different search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Fetch and read the text content of a web page at the given URL.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  📄 Fetching: {url}");
        try
        {
            var html = await httpClient.GetStringAsync(url, cancellationToken);
            var text = StripHtml(html);
            return text.Length > 4000
                ? string.Concat(text.AsSpan(0, 4000), "\n[Content truncated]")
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string ParseSearchResults(string html)
    {
        var results = new StringBuilder();
        int count = 0;
        int pos = 0;

        while (count < 5)
        {
            pos = html.IndexOf("class=\"result__a\"", pos, StringComparison.Ordinal);
            if (pos < 0) break;

            // Extract href
            int searchBack = Math.Min(pos, 300);
            var hrefStart = html.LastIndexOf("href=\"", pos, searchBack, StringComparison.Ordinal);
            if (hrefStart < 0) { pos++; continue; }
            hrefStart += 6;
            var hrefEnd = html.IndexOf('"', hrefStart);
            if (hrefEnd < 0) { pos++; continue; }
            var href = WebUtility.HtmlDecode(html[hrefStart..hrefEnd]);

            // Extract title
            var tagEnd = html.IndexOf('>', pos);
            if (tagEnd < 0) { pos++; continue; }
            var closeTag = html.IndexOf("</a>", tagEnd, StringComparison.Ordinal);
            if (closeTag < 0) { pos++; continue; }
            var title = StripHtml(html[(tagEnd + 1)..closeTag]);

            // Extract snippet
            string snippet = "";
            var snippetPos = html.IndexOf("class=\"result__snippet\"", closeTag, StringComparison.Ordinal);
            if (snippetPos >= 0 && snippetPos - closeTag < 2000)
            {
                var sTagEnd = html.IndexOf('>', snippetPos);
                if (sTagEnd >= 0)
                {
                    var sCloseTag = html.IndexOf("</", sTagEnd, StringComparison.Ordinal);
                    if (sCloseTag >= 0)
                        snippet = StripHtml(html[(sTagEnd + 1)..sCloseTag]);
                }
            }

            if (!string.IsNullOrWhiteSpace(title))
            {
                count++;
                results.AppendLine($"{count}. {title.Trim()}");
                if (!string.IsNullOrWhiteSpace(href))
                    results.AppendLine($"   URL: {href}");
                if (!string.IsNullOrWhiteSpace(snippet))
                    results.AppendLine($"   {snippet.Trim()}");
                results.AppendLine();
            }

            pos = closeTag + 1;
        }

        return results.ToString();
    }

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(
            html, @"<(script|style)[^>]*>.*?</\1>", "",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"\s+", " ").Trim();
        return text;
    }
}

/// <summary>Provides note-taking tools for the research agent.</summary>
public sealed class Notepad
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note. Use this to record each important finding during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content or finding to save")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: {title}");
        return $"Note '{title}' saved. Total notes: {_notes.Count}.";
    }

    [Description("Retrieve all saved research notes. Call this to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet. Use save_note to record findings first.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== {_notes.Count} Research Note(s) ===\n");
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

